const raw = $input.all().map(i => i.json);
const businesses = raw.length === 1 && Array.isArray(raw[0]) ? raw[0] : raw;
const results = [];
for (const biz of businesses) {
  const id = biz.business_id || biz.name;
  if (!id || id === '_template') continue;
  results.push({ json: { businessId: id, businessName: biz.name || id, businessPath: 'memory-bank/businesses/' + id, site_url: biz.site_url || '', repo_name: biz.repo_name || id } });
}
if (results.length === 0) results.push({ json: { businessId: 'bayflow', businessName: 'BayFlow', businessPath: 'memory-bank/businesses/bayflow', site_url: '', repo_name: 'bayflow' } });
return results;

const llmOutput = $('Finance LLM Chain').first().json.text || '';

// Extract JSON between markers
const startMarker = '===METRICS_JSON_START===';
const endMarker = '===METRICS_JSON_END===';
const startIdx = llmOutput.indexOf(startMarker);
const endIdx = llmOutput.indexOf(endMarker);

let metrics = {
  mrr: 0,
  revenue_organic: 0,
  revenue_paid: 0,
  revenue_direct: 0,
  revenue_referral: 0,
  traffic_total: 0,
  traffic_organic: 0,
  traffic_paid: 0,
  traffic_direct: 0,
  traffic_referral: 0,
  signups: 0,
  trials: 0,
  conversions: 0,
  churn_count: 0,
  churn_mrr: 0,
  support_tickets: 0,
  support_auto_resolved: 0,
  ad_spend: 0,
  ai_api_cost: 0
};

if (startIdx !== -1 && endIdx !== -1) {
  const jsonStr = llmOutput.substring(startIdx + startMarker.length, endIdx).trim();
  try {
    const parsed = JSON.parse(jsonStr);
    // Merge parsed values over defaults so all keys are present
    metrics = { ...metrics, ...parsed };
  } catch (e) {
    // If parse fails, keep defaults (all zeros)
  }
}

// Strip the metrics block from the report text for clean GitHub output
let reportText = llmOutput;
if (startIdx !== -1 && endIdx !== -1) {
  reportText = llmOutput.substring(0, startIdx).trim();
}

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    metrics,
    reportText,
    date: today
  }
}];
